class Solution:
    def reorderedPowerOf2(self, n: int) -> bool:
        def count_digits(num):
            count = [0] * 10
            while num:
                count[num % 10] += 1
                num //= 10
            return tuple(count)

        n_count = count_digits(n)
        for i in range(31):
            if count_digits(1 << i) == n_count:
                return True
        return False
